import{_ as e,o,c as t,a2 as r}from"./chunks/framework.COr20JJv.js";const d=JSON.parse('{"title":"项目介绍","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lygenealogy/introduction.md","filePath":"projects/lygenealogy/introduction.md"}'),l={name:"projects/lygenealogy/introduction.md"};function n(i,a,s,h,g,u){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to &quot;项目介绍&quot;">​</a></h1><blockquote><p>编辑日期：2026-03-13<br> 以 <a href="https://github.com/quxiangshun/ly-genealogy" target="_blank" rel="noreferrer">GitHub 仓库</a> 当前版本为准。</p></blockquote><h2 id="关于-lygenealogy" tabindex="-1">关于 LyGenealogy <a class="header-anchor" href="#关于-lygenealogy" aria-label="Permalink to &quot;关于 LyGenealogy&quot;">​</a></h2><p>LyGenealogy（屈氏宗谱）是基于 <strong>Node.js</strong> 技术栈的开源族谱数字化平台，包含<strong>公共前端</strong>（Nuxt 3，H5 移动端适配）、<strong>管理后台</strong>（Vue 3 + Element Plus）和 <strong>REST API</strong>（Express + TypeScript），采用 pnpm Monorepo 管理多包。</p><ul><li><strong>GitHub</strong>：<a href="https://github.com/quxiangshun/ly-genealogy" target="_blank" rel="noreferrer">quxiangshun/ly-genealogy</a></li><li><strong>在线演示</strong>：见仓库说明或部署文档中的访问地址</li></ul><h3 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h3><p>传统纸质族谱在保存、检索与共享方面存在明显局限。LyGenealogy 将族谱数字化，提供族谱管理、世系展示、亲属查询与文化展示，方便宗亲寻根问祖与姓氏文化传承。</p><h3 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h3><ul><li><strong>数字化存档</strong>：族谱数据持久化存储（SQLite），支持多族谱、多地区</li><li><strong>智能检索</strong>：成员搜索、字辈查询、亲缘关系递归展示</li><li><strong>世系可视化</strong>：树形世系与关系展示</li><li><strong>多端与 SEO</strong>：公共前端支持 SSR/SSG/ISR、PWA，移动端友好</li><li><strong>文化传承</strong>：百科、新闻、姓氏文化等内容的统一展示与管理</li></ul><h2 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to &quot;功能概览&quot;">​</a></h2><h3 id="公共前端-无需登录" tabindex="-1">公共前端（无需登录） <a class="header-anchor" href="#公共前端-无需登录" aria-label="Permalink to &quot;公共前端（无需登录）&quot;">​</a></h3><ul><li>门户首页、族谱库列表与族谱详情（谱籍、字辈摘要）</li><li>字辈查询、姓氏文化、百科与新闻动态</li><li>成员搜索与亲缘关系查询（脱敏策略以实际为准）</li></ul><h3 id="管理后台-需登录" tabindex="-1">管理后台（需登录） <a class="header-anchor" href="#管理后台-需登录" aria-label="Permalink to &quot;管理后台（需登录）&quot;">​</a></h3><ul><li>族谱 / 成员 / 字辈等数据的新增与编辑</li><li>世系树、成员列表等管理能力</li></ul><h3 id="技术特点" tabindex="-1">技术特点 <a class="header-anchor" href="#技术特点" aria-label="Permalink to &quot;技术特点&quot;">​</a></h3><ul><li><strong>前后端分离</strong>：REST API + Nuxt 公共前端 + Vue Admin SPA</li><li><strong>Monorepo</strong>：<code>packages/server</code>、<code>packages/web</code>、<code>packages/admin</code> 统一仓库、统一构建与部署</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>各姓氏宗族的族谱数字化与长期维护</li><li>宗亲寻根、亲属关系查询</li><li>姓氏文化整理与对外展示</li></ul><h2 id="开源协议" tabindex="-1">开源协议 <a class="header-anchor" href="#开源协议" aria-label="Permalink to &quot;开源协议&quot;">​</a></h2><p>采用 <strong>Apache License 2.0</strong>。系统支持多姓氏扩展，可配置或扩展其他姓氏的展示与数据。</p>',20)])])}const p=e(l,[["render",n]]);export{d as __pageData,p as default};
